#include <stdio.h>
#include <cuda_runtime.h>

#define BS 16

#define AA(_i,_j) a[offset*size+_i*size+_j+offset]
#define BB(_i,_j) a[_i*size+_j]

__global__ void lud_diagonal_kernel(float* a, int size, int offset) {
    int i = blockIdx.x * blockDim.x + threadIdx.x;
    int j = blockIdx.y * blockDim.y + threadIdx.y;

    if (i < BS && j < BS) {
        if (i == j) {
            float sum = 0;
            for (int k = 0; k < i; k++) {
                sum += AA(i, k) * AA(k, j);
            }
            AA(i, j) -= sum;
        } else if (i < j) {
            float sum = 0;
            for (int k = 0; k < i; k++) {
                sum += AA(i, k) * AA(k, j);
            }
            AA(i, j) -= sum;
        }
    }
}

__global__ void lud_perimeter_kernel(float* a, int size, int offset, int chunk_idx) {
    int i = blockIdx.x * blockDim.x + threadIdx.x;
    int j = blockIdx.y * blockDim.y + threadIdx.y;

    if (i < BS && j < BS) {
        int i_global = offset + i;
        int j_global = offset + BS + chunk_idx * BS + j;

        float sum = 0;
        for (int k = 0; k < BS; k++) {
            sum += a[i_global * size + offset + k] * a[offset + k * size + j_global];
        }
        a[i_global * size + j_global] -= sum;
    }
}

__global__ void lud_interior_kernel(float* a, int size, int offset, int chunk_idx) {
    int i = blockIdx.x * blockDim.x + threadIdx.x;
    int j = blockIdx.y * blockDim.y + threadIdx.y;

    if (i < BS && j < BS) {
        int i_global = offset + BS + chunk_idx / BS * BS + i;
        int j_global = offset + BS + chunk_idx % BS * BS + j;

        float sum = 0;
        for (int k = 0; k < BS; k++) {
            sum += a[i_global * size + offset + k * size + k] * a[k * size + j_global];
        }
        a[i_global * size + j_global] -= sum;
    }
}

void lud_cuda(float *a, int size) {
    int offset;
    int chunk_idx;

    float *d_a;
    cudaMalloc((void**)&d_a, size * size * sizeof(float));
    cudaMemcpy(d_a, a, size * size * sizeof(float), cudaMemcpyHostToDevice);

    for (offset = 0; offset < size - BS; offset += BS) {
        lud_diagonal_kernel<<<dim3(1, 1), dim3(BS, BS)>>>(d_a, size, offset);

        for (chunk_idx = 0; chunk_idx < (size - offset - BS) / BS; chunk_idx++) {
            lud_perimeter_kernel<<<dim3(1, 1), dim3(BS, BS)>>>(d_a, size, offset, chunk_idx);
        }

        int chunks_in_inter_row = (size - offset - BS) / BS;
        for (chunk_idx = 0; chunk_idx < chunks_in_inter_row * chunks_in_inter_row; chunk_idx++) {
            lud_interior_kernel<<<dim3(1, 1), dim3(BS, BS)>>>(d_a, size, offset, chunk_idx);
        }
    }

    lud_diagonal_kernel<<<dim3(1, 1), dim3(BS, BS)>>>(d_a, size, offset);

    cudaMemcpy(a, d_a, size * size * sizeof(float), cudaMemcpyDeviceToHost);
    cudaFree(d_a);
}
